import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";
import { playWave, playPoint, playGesture, playScan, playWalkCycle, resetPose } from "../three/robot.js";
import { showSpeechBubble, hideSpeechBubble } from "../components/speechBubble.js";

gsap.registerPlugin(ScrollTrigger);

const MESSAGES = {
  home:       "Hi — I'm your guide. Scroll to explore.",
  solutions:  "Six domains. Pick one to dive in.",
  operations: "Cloud · SOC · NOC — operations that never sleep.",
  service:    "Here's how we work. Scroll horizontally →",
  contact:    "Let's connect — type your message.",
};

/* All transforms apply to the `orient` group — never the root. The `bob`
 * child group (idle loop) layers underneath without tween conflicts.
 *
 * Anchors are tuned so the robot never overlaps text columns:
 *   - Home: docked top-right, hovering away from the centered hero
 *   - Solutions: tucked far bottom-right, smaller, well below the grid
 *   - Operations: docked left, ride alongside the right-side panels
 *   - Service: floating bottom-right corner, tiny
 *   - Contact: bottom-right of viewport, larger, behind the form column
 */

const TW = { overwrite: "auto", ease: "power3.inOut", duration: 1.2 };
let activeSection = null;

// Compensate for narrow viewports — push robot further off-axis
function widthScale() {
  const w = window.innerWidth;
  if (w < 760) return 0.6;
  if (w < 1100) return 0.85;
  return 1;
}

export function setupRobotScroll(robot) {
  const orient = robot.userData.orient;

  function setSection(id) {
    if (activeSection === id) return;
    activeSection = id;
    if (!document.body.classList.contains("card-expanded")) {
      showSpeechBubble(MESSAGES[id]);
    }
  }

  /* World half-width at z=0 ≈ 2.84 units (FOV 42°, cam z=7.4).
   * Keep robot x positions within ±2.6 so it stays on screen.
   * widthScale() shrinks positions further on narrow viewports. */

  // ===== HOME — right column, large and prominent =====
  ScrollTrigger.create({
    trigger: "#home",
    start: "top top",
    end: "bottom top",
    onEnter: onHome,
    onEnterBack: onHome,
  });

  function onHome() {
    setSection("home");
    resetPose(robot);
    const w = widthScale();
    gsap.to(orient.position, { x: 2.4 * w, y: -0.4, z: -0.3, ...TW });
    gsap.to(orient.rotation, { x: 0, y: -0.32, z: 0, ...TW });
    gsap.to(orient.scale,    { x: 0.88, y: 0.88, z: 0.88, ...TW });
    gsap.delayedCall(0.45, () => playWave(robot));
  }

  // ===== SOLUTIONS — bottom-right corner, small so cards breathe =====
  ScrollTrigger.create({
    trigger: "#solutions",
    start: "top 60%",
    end: "bottom 40%",
    onEnter: onSolutions,
    onEnterBack: onSolutions,
  });

  function onSolutions() {
    setSection("solutions");
    resetPose(robot);
    const w = widthScale();
    gsap.to(orient.scale,    { x: 0.52, y: 0.52, z: 0.52, ...TW });
    gsap.to(orient.position, { x: 2.55 * w, y: -1.8, z: 0.5, ...TW });
    gsap.to(orient.rotation, { x: 0, y: -0.42, z: 0, ...TW });
    gsap.delayedCall(0.6, () => playPoint(robot));
  }

  // ===== OPERATIONS — docked left, watching the right-side panels =====
  ScrollTrigger.create({
    trigger: "#operations",
    start: "top 60%",
    end: "bottom 40%",
    onEnter: onOperations,
    onEnterBack: onOperations,
  });

  function onOperations() {
    setSection("operations");
    resetPose(robot);
    const w = widthScale();
    // Smaller scale + further left → clears content starting at 22vw padding
    gsap.to(orient.scale,    { x: 0.60, y: 0.60, z: 0.60, ...TW });
    gsap.to(orient.position, { x: -2.58 * w, y: -0.5, z: 0.2, ...TW });
    gsap.to(orient.rotation, { x: 0, y: 0.42, z: 0, ...TW });
    gsap.delayedCall(0.55, () => playScan(robot));
  }

  // ===== SERVICE — right side, clearly visible beside the 2-col cards =====
  ScrollTrigger.create({
    trigger: "#service",
    start: "top 60%",
    end: "bottom 40%",
    onEnter: onService,
    onEnterBack: onService,
  });

  function onService() {
    setSection("service");
    resetPose(robot);
    const w = widthScale();
    gsap.to(orient.scale,    { x: 0.72, y: 0.72, z: 0.72, ...TW });
    gsap.to(orient.position, { x: 2.25 * w, y: -0.6, z: 0.4, ...TW });
    gsap.to(orient.rotation, { x: 0, y: -0.38, z: 0, ...TW });
    gsap.delayedCall(0.5, () => playGesture(robot));
  }

  // ===== CONTACT — right side, away from form column =====
  ScrollTrigger.create({
    trigger: "#contact",
    start: "top 70%",
    end: "bottom 40%",
    onEnter: onContact,
    onEnterBack: onContact,
    onLeave: () => hideSpeechBubble(),
  });

  function onContact() {
    setSection("contact");
    resetPose(robot);
    const w = widthScale();
    gsap.to(orient.scale,    { x: 0.72, y: 0.72, z: 0.72, ...TW });
    gsap.to(orient.position, { x: 2.4 * w, y: -1.2, z: 0.6, ...TW });
    gsap.to(orient.rotation, { x: 0, y: -0.5, z: 0, ...TW });
    gsap.delayedCall(0.5,  () => playWalkCycle(robot, 1.4));
    gsap.delayedCall(1.65, () => playWave(robot));
  }

  // Card-expanded → hide bubble; restore on collapse
  const observer = new MutationObserver(() => {
    if (document.body.classList.contains("card-expanded")) {
      hideSpeechBubble();
    } else if (activeSection) {
      showSpeechBubble(MESSAGES[activeSection]);
    }
  });
  observer.observe(document.body, { attributes: true, attributeFilter: ["class"] });

  // Reposition on resize so the anchor stays viewport-relative
  window.addEventListener("resize", () => {
    if (!activeSection) return;
    ({ home: onHome, solutions: onSolutions, operations: onOperations,
       service: onService, contact: onContact })[activeSection]?.();
  });
}

export function celebrateContactSuccess(robot) {
  const { orient } = robot.userData;
  playWave(robot);
  gsap.to(orient.scale, {
    x: 1.1, y: 1.1, z: 1.1,
    duration: 0.4,
    yoyo: true,
    repeat: 1,
    ease: "power2.inOut",
    overwrite: "auto",
  });
}
